%  Вычисляет невязку системы уравнений

function y = nonlinear_equations_system_full_4(x, N, T, E_kin_rab)
    y = zeros(4 * T, 1);
    %  начальные условия по кинетической энергии из графика
    y(1:3, 1) = [0.5*sum((A(0, x, N, 1) .* x(1            :N(1))        .* cos(x((sum(N)+1)          :(sum(N)+N(1))))      + A1(0, x, N, 1) .* sin(x((sum(N)+1)          :(sum(N)+N(1))))).^2)      - E_kin_rab(1);
                 0.5*sum((A(0, x, N, 2) .* x((N(1)+1)     :(N(1)+N(2))) .* cos(x((sum(N)+N(1)+1)     :(sum(N)+N(1)+N(2)))) + A1(0, x, N, 2) .* sin(x((sum(N)+N(1)+1)     :(sum(N)+N(1)+N(2))))).^2) - E_kin_rab(2);
                 0.5*sum((A(0, x, N, 3) .* x((N(1)+N(2)+1):sum(N))      .* cos(x((sum(N)+N(1)+N(2)+1):(2*sum(N))))         + A1(0, x, N, 3) .* sin(x((sum(N)+N(1)+N(2)+1):(2*sum(N))))).^2)         - E_kin_rab(3)];

    for t_id = 0:(T - 1)  %  кинетика полной энергии
        t = t_id;
        a = 0.5 * sum((A(t, x, N, 1) .* x(1            :N(1))        .* cos(x(1            :N(1))        * t + x((sum(N)+1)          :(sum(N)+N(1))))      + A1(t, x, N, 1) .* sin(x(1            :N(1))        * t + x((sum(N)+1)          :(sum(N)+N(1))))).^2      + (A(t, x, N, 1) .* x(1            :N(1))        .* sin(x(1            :N(1))        * t + x((sum(N)+1)          :(sum(N)+N(1))))).^2);
        b = 0.5 * sum((A(t, x, N, 2) .* x((N(1)+1)     :(N(1)+N(2))) .* cos(x((N(1)+1)     :(N(1)+N(2))) * t + x((sum(N)+N(1)+1)     :(sum(N)+N(1)+N(2)))) + A1(t, x, N, 2) .* sin(x((N(1)+1)     :(N(1)+N(2))) * t + x((sum(N)+N(1)+1)     :(sum(N)+N(1)+N(2))))).^2 + (A(t, x, N, 2) .* x((N(1)+1)     :(N(1)+N(2))) .* sin(x((N(1)+1)     :(N(1)+N(2))) * t + x((sum(N)+N(1)+1)     :(sum(N)+N(1)+N(2))))).^2);
        r = 0.5 * sum((A(t, x, N, 3) .* x((N(1)+N(2)+1):sum(N))      .* cos(x((N(1)+N(2)+1):sum(N))      * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))         + A1(t, x, N, 3) .* sin(x((N(1)+N(2)+1):sum(N))      * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))).^2         + (A(t, x, N, 3) .* x((N(1)+N(2)+1):sum(N))      .* sin(x((N(1)+N(2)+1):sum(N))      * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))).^2);
        y((1:3) + 3 * (t_id + 1), 1) = [...
            0.5 * sum(2 * A(t, x, N, 1) .* A1(t, x, N, 1) .* (x(1:N(1)).^2) ...
            +            A1(t, x, N, 1).^2                .*  x(1:N(1))               .*  sin(2*(x(1:N(1)) *           t + x((sum(N)+1):(sum(N)+N(1))))) ...
            +             A(t, x, N, 1) .* A2(t, x, N, 1) .*  x(1:N(1))               .*  sin(2*(x(1:N(1)) *           t + x((sum(N)+1):(sum(N)+N(1))))) ...
            +         2 * A(t, x, N, 1) .* A1(t, x, N, 1) .* (x(1:N(1)).^2)           .*  cos(2*(x(1:N(1)) *           t + x((sum(N)+1):(sum(N)+N(1))))) ...
            +        2 * A1(t, x, N, 1) .* A2(t, x, N, 1) .*                             (sin(   x(1:N(1)) *           t + x((sum(N)+1):(sum(N)+N(1)))).^2) ...
            +            A1(t, x, N, 1).^2                .*  x(1:N(1))               .*  sin(2*(x(1:N(1)) *           t + x((sum(N)+1):(sum(N)+N(1)))))) ...
            - x(2*sum(N)+2) * a * (b^2) + x(2*sum(N)+1) * (a^2) * b - x(2*sum(N)+4) * a * (r^2) + x(2*sum(N)+3) * (a^2) * r;

            0.5 * sum(2 * A(t, x, N, 2) .* A1(t, x, N, 2) .* (x((N(1)+1):(N(1)+N(2))).^2) ...
            +            A1(t, x, N, 2).^2                .*  x((N(1)+1):(N(1)+N(2)))           .*  sin(2*(x((N(1)+1):(N(1)+N(2))) *   t + x((sum(N)+N(1)+1):(sum(N)+N(1)+N(2))))) ...
            +             A(t, x, N, 2) .* A2(t, x, N, 2) .*  x((N(1)+1):(N(1)+N(2)))           .*  sin(2*(x((N(1)+1):(N(1)+N(2))) *   t + x((sum(N)+N(1)+1):(sum(N)+N(1)+N(2))))) ...
            +         2 * A(t, x, N, 2) .* A1(t, x, N, 2) .* (x((N(1)+1):(N(1)+N(2))).^2)       .*  cos(2*(x((N(1)+1):(N(1)+N(2))) *   t + x((sum(N)+N(1)+1):(sum(N)+N(1)+N(2))))) ...
            +        2 * A1(t, x, N, 2) .* A2(t, x, N, 2) .*                                       (sin(   x((N(1)+1):(N(1)+N(2))) *   t + x((sum(N)+N(1)+1):(sum(N)+N(1)+N(2)))).^2) ...
            +            A1(t, x, N, 2).^2                .* x((N(1)+1):(N(1)+N(2)))                     .*  sin(2*(x((N(1)+1):(N(1)+N(2))) *   t + x((sum(N)+N(1)+1):(sum(N)+N(1)+N(2)))))) ...
            - x(2*sum(N)+1) * (a^2) * b + x(2*sum(N)+2) * a * (b^2) - x(2*sum(N)+6) * b * (r^2) + x(2*sum(N)+5) * (b^2) * r;

            0.5 * sum(2 * A(t, x, N, 3) .* A1(t, x, N, 3) .* (x((N(1)+N(2)+1):sum(N)).^2) ...
            +            A1(t, x, N, 3).^2                .*  x((N(1)+N(2)+1):sum(N))     .*  sin(2*(x((N(1)+N(2)+1):sum(N)) * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))) ...
            +             A(t, x, N, 3) .* A2(t, x, N, 3) .*  x((N(1)+N(2)+1):sum(N))     .*  sin(2*(x((N(1)+N(2)+1):sum(N)) * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))) ...
            +         2 * A(t, x, N, 3) .* A1(t, x, N, 3) .* (x((N(1)+N(2)+1):sum(N)).^2) .*  cos(2*(x((N(1)+N(2)+1):sum(N)) * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))) ...
            +        2 * A1(t, x, N, 3) .* A2(t, x, N, 3) .*                                 (sin(   x((N(1)+N(2)+1):sum(N)) * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N)))).^2) ...
            +            A1(t, x, N, 3).^2                .*  x((N(1)+N(2)+1):sum(N))     .*  sin(2*(x((N(1)+N(2)+1):sum(N)) * t + x((sum(N)+N(1)+N(2)+1):(2*sum(N)))))) ...
            - x(2*sum(N)+3) * (a^2) * r + x(2*sum(N)+4) * a * (r^2) - x(2*sum(N)+5) * (b^2) * r + x(2*sum(N)+6) * b * (r^2)];
    end

    for t_id = 0:(T - 1)  %  закон сохранения полной энергии, приравниваем к t==0
        t = t_id;
        y(3 * T + t_id + 1, 1) = 0.5 * (...
              sum((A(t, x, N, 1) .*                   x(1:N(1))).^2 ...
            +      A(t, x, N, 1) .* A1(t, x, N, 1) .* x(1:N(1))               .* sin(2*(x(1:N(1)) .* t + x((sum(N)+1):(sum(N)+N(1))))) ...
            +    (A1(t, x, N, 1) .*                                              sin(   x(1:N(1)) .* t + x((sum(N)+1):(sum(N)+N(1))))).^2) ...
            ...
            + sum((A(t, x, N, 2) .*                   x((N(1)+1):(N(1)+N(2)))).^2 ...
            +      A(t, x, N, 2) .* A1(t, x, N, 2) .* x((N(1)+1):(N(1)+N(2))) .* sin(2*(x((N(1)+1):(N(1)+N(2))) .* t + x((sum(N)+N(1)+1):(sum(N)+N(1)+N(2))))) ...
            +    (A1(t, x, N, 2) .*                                              sin(   x((N(1)+1):(N(1)+N(2))) .* t + x((sum(N)+N(1)+1):(sum(N)+N(1)+N(2))))).^2) ...
            ...
            + sum((A(t, x, N, 3) .*                   x((N(1)+N(2)+1):sum(N))).^2 ...
            +      A(t, x, N, 3) .* A1(t, x, N, 3) .* x((N(1)+N(2)+1):sum(N)) .* sin(2*(x((N(1)+N(2)+1):sum(N)) .* t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))) ...
            +    (A1(t, x, N, 3) .*                                              sin(   x((N(1)+N(2)+1):sum(N)) .* t + x((sum(N)+N(1)+N(2)+1):(2*sum(N))))).^2)) ...
            ...
            - sum(E_kin_rab(1:3));
    end
end